import { useState, useEffect } from "react";
import { T } from "../../assets/styles/theme";
import { Btn, Card, Badge, Avatar, Input, Select, StatCard, Table, Tabs, ProgressBar, DonutChart, MiniBarChart, PageHeader, ProfileAlert, Modal, calcProfileCompletion } from "../../components/UI";
import { DashLayout } from "../../components/Layout";
import {
  getTeacherProfile, updateTeacherProfile,
  getTeacherCourses, getTeacherAssignments,
  getSubmissionsForAssignment, gradeSubmission,
  markAttendance, getAttendanceForDate,
  createTeacherAnnouncement, getTeacherNotifications,
  getActiveDepartments, getAllStudents,
  getParentProfile, updateParentProfile,
  getMyChildren, linkChild,
  getChildFees,
  getParentNotifications,
} from "../../api/auth";

// ════════════════════════════════════════════════════════════════════════════════
// TEACHER PAGES
// ════════════════════════════════════════════════════════════════════════════════

export const TeacherOverview = () => (
  <div className="fade-up">
    <PageHeader title="Teacher Dashboard" subtitle="Welcome, Prof. Priya! Here's your teaching overview." />
    <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 18, marginBottom: 24 }}>
      <StatCard icon="👨‍🎓" label="Total Students" value="248" change="Across 4 courses" color={T.accent} />
      <StatCard icon="📚" label="Active Courses" value="4" change="2 live this week" color={T.primaryL} />
      <StatCard icon="📝" label="Pending Grading" value="12" change="Assignments to grade" color={T.accentY} />
      <StatCard icon="⭐" label="My Rating" value="4.8" change="By students" color={T.accentG} />
    </div>
    <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr", gap: 20 }}>
      <div>
        <Card style={{ marginBottom: 20 }}>
          <div style={{ fontFamily: "Syne", fontWeight: 700, fontSize: 15, marginBottom: 16 }}>My Courses</div>
          {[{ icon: "💻", title: "Full Stack Web Development", students: 82, progress: 72, pending: 5 }, { icon: "📊", title: "Data Science & ML", students: 96, progress: 55, pending: 7 }].map(c => (
            <div key={c.title} style={{ background: T.bg3, borderRadius: 12, padding: 16, marginBottom: 12 }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
                <div><div style={{ fontFamily: "Syne", fontWeight: 700, fontSize: 14 }}>{c.title}</div><div style={{ fontSize: 12, color: T.muted, marginTop: 2 }}>CS Department</div></div>
                <Badge type="success">Active</Badge>
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 10 }}>
                {[["Students", c.students, T.accent], ["Avg Progress", `${c.progress}%`, T.primaryL], ["Pending", c.pending, T.accentY]].map(([l, v, co]) => (
                  <div key={l} style={{ background: T.card, borderRadius: 8, padding: 10, textAlign: "center" }}>
                    <div style={{ fontFamily: "Syne", fontSize: 18, fontWeight: 800, color: co }}>{v}</div>
                    <div style={{ fontSize: 11, color: T.muted }}>{l}</div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </Card>
        <Card>
          <div style={{ fontFamily: "Syne", fontWeight: 700, fontSize: 15, marginBottom: 14 }}>Recent Submissions</div>
          <Table columns={["Student", "Assignment", "Submitted", "Action"]} rows={[
            [<div style={{ display: "flex", gap: 8, alignItems: "center" }}><Avatar name="Ananya Reddy" size={26} />Ananya R</div>, "EDA Analysis", "2 hrs ago", <Btn size="xs" variant="primary">Grade</Btn>],
            [<div style={{ display: "flex", gap: 8, alignItems: "center" }}><Avatar name="Rahul Mehta" size={26} />Rahul M</div>, "JS Quiz", "5 hrs ago", <Btn size="xs" variant="primary">Grade</Btn>],
          ]} />
        </Card>
      </div>
      <div>
        <Card style={{ marginBottom: 18 }}>
          <div style={{ fontFamily: "Syne", fontWeight: 700, marginBottom: 14 }}>Today's Schedule</div>
