            </div>
          ))}
          {outstanding > 0 && <><Btn variant="accent" full style={{ marginTop: 16 }}>💳 Pay ₹{outstanding.toLocaleString("en-IN")} Now</Btn><div style={{ fontSize: 11, color: T.muted, textAlign: "center", marginTop: 10 }}>Secured by Razorpay Payment Gateway</div></>}
