          <div style={{ display: "flex", gap: 10 }}><Avatar name="A" size={30} color={T.accent} /><div style={{ background: T.card2, borderRadius: "10px 10px 10px 2px", padding: "10px 14px", maxWidth: "70%", fontSize: 13 }}>Ananya is doing very well! She scored 88/100 in the recent quiz.</div></div>
        </div>
        <div style={{ display: "flex", gap: 10 }}>
          <input placeholder="Type a message..." style={{ flex: 1, background: T.bg3, border: `1.5px solid ${T.border}`, borderRadius: 9, padding: "10px 14px", fontSize: 13, color: T.text, outline: "none", fontFamily: "DM Sans" }} />
          <Btn variant="danger">Send</Btn>
        </div>
      </Card>
      <Card>
        <div style={{ fontFamily: "Syne", fontWeight: 700, marginBottom: 10 }}>Teachers</div>
        {[{ name: "Dr. Anand Raj", dept: "Data Science", online: true }, { name: "Mr. Ravi Shankar", dept: "Cyber Security", online: false }].map(t => (
          <div key={t.name} style={{ display: "flex", gap: 10, alignItems: "center", background: T.bg3, borderRadius: 9, padding: 10, marginBottom: 8, cursor: "pointer" }}>
